cd ~/.claude/projects/-Users-matthew-khoriaty-Desktop-Northwestern-Classes-Senior-spring-software-studio-project-stay-in-touch/ && for f in *.jsonl; do
  echo "=== $f ==="
  python3 -c "
import json, sys
with open('$f') as fh:
    user_count = 0
    first_user = None
    for line in fh:
        try:
            obj = json.loads(line)
            if obj.get('type') == 'user':
                msg = obj.get('message', {})
                content = msg.get('content', '')
                if isinstance(content, list):
                    text = ''
                    for c in content:
                        if c.get('type') == 'text':
                            text += c.get('text', '')
                        elif c.get('type') == 'tool_result':
                            text = None
                            break
                    if text is None:
                        continue
                    content = text
                if not content:
                    continue
                if '<system-reminder>' in content and '</system-reminder>' in content:
                    # Strip reminders
                    import re
                    content = re.sub(r'<system-reminder>.*?</system-reminder>', '', content, flags=re.DOTALL).strip()
                if not content.strip():
                    continue
                user_count += 1
                if first_user is None:
                    first_user = content
        except Exception:
            pass
    print(f'User messages: {user_count}')
    if first_user:
        print(f'First: {first_user[:500]}')
"
done

